import kotlinx.coroutines.*
import kotlinx.coroutines.test.*
import kotlin.test.*

/**
 * Test to verify SharedFlow.toList(destination) properly collects into the provided destination.
 * This tests the fix for the issue where the destination parameter was ignored.
 */
class SharedFlowToListTest {

    @Test
    fun testSharedFlowToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 2)
        val destination = mutableListOf<Int>()

        // Emit values
        sharedFlow.emit(1)
        sharedFlow.emit(2)

        // Launch a collector that will be cancelled
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(destination)
        }

        // Give some time for collecting
        yield()

        // Emit more values
        sharedFlow.emit(3)
        yield()

        // Cancel the collection
        job.cancel()

        // The destination should have collected the emitted values
        // With replay=2, we get the last 2 replay values plus any new values emitted during collection
        assertEquals(listOf(1, 2, 3), destination)
    }

    @Test
    fun testSharedFlowToSetWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 2)
        val destination = mutableSetOf<Int>()

        // Emit values (with a duplicate to test Set behavior)
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(1)

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toSet(destination)
        }

        yield()

        sharedFlow.emit(3)
        yield()

        job.cancel()

        // Should contain unique values collected
        assertEquals(setOf(1, 2, 3), destination)
    }

    @Test
    fun testSharedFlowMultipleEmissionsToList() = runTest {
        val sharedFlow = MutableSharedFlow<String>()
        val destination = mutableListOf<String>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(destination)
        }

        repeat(5) { i ->
            sharedFlow.emit("item$i")
            yield()
        }

        job.cancel()

        assertEquals(listOf("item0", "item1", "item2", "item3", "item4"), destination)
    }

    @Test
    fun testSharedFlowToListWithReplay() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 3)
        val destination = mutableListOf<Int>()

        // Emit initial replay values
        sharedFlow.emit(10)
        sharedFlow.emit(20)
        sharedFlow.emit(30)

        // Start collecting - replay buffer should be collected first
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(destination)
        }

        yield()

        // Emit new values
        sharedFlow.emit(40)
        yield()

        job.cancel()

        // Should have all replay values plus new values
        assertEquals(listOf(10, 20, 30, 40), destination)
    }
}"}

